<script>
import SupportList from '@/components/Support.vue'
export default {
  name: 'Article',
  components: {
    SupportList
  },
  data() {
    return {
      gameInfo: [],
      tgData: [],
      settingList: [],
      colorList: [],
      authorGameList: [],
      authorName: '',
      gameType: ['primary', 'success', 'default', 'info', 'warning', 'danger', 'add1', 'add2', 'add3', 'add4', 'add5', 'add6'],
      id: this.$route.params.id,
      num: 0,
      vote: ''
    }
  },
  created() {
    this.getSetting()
    this.getArticleSetting()
    this.getTg()
  },
  computed: {
    filteredGameListNew() {
      return this.gameListNew.slice(0, this.showNumber)
    },
  },
  mounted() {},
  methods: {
    getSetting() {
      const timeStamp = new Date().getTime()
      // 获取网站配置，存入本地储存
      this.$http.get('static/data/setting.json' + '?' + timeStamp).then(game => {
        // 如果本地有记录，对比配置版本号是否一致
        if(localStorage.getItem('settingList') && (game.data[0].version === JSON.parse(localStorage.getItem('settingList'))[0].version)){
          // 读取本地json
          this.getStaticData()
        } else {
          // 读取远程json
          this.getData()
          // 覆盖本地版本号
          localStorage.setItem('settingList', JSON.stringify(game.data))
        }
      })
    },
    getData() {
      var timeStamp = new Date().getTime()
      this.$http.get('static/data/games.json' + '?' + timeStamp).then(game => {
        localStorage.setItem('gameList', JSON.stringify(game.data))
        // 获取当前游戏详情
        var currentGame = game.data.find(item => item.path === this.id)
        if (currentGame) {
          this.gameInfo.push(currentGame)
          this.authorName = currentGame.author
          document.title = currentGame.title + ' - Git游戏 - gityx.com'
          this.num = 1
          this.authorGameList = game.data.filter(item => item.author === this.authorName && item.path !== this.id)
        }
        if (this.num < 1) {
          //                            console.log(this.num)
          this.$router.push({
            path: '/'
          })
        }
      },
      game => {
        console.log('error')
      }
      )
    },
    getStaticData() {
      var gameArr = JSON.parse(localStorage.getItem('gameList'))
      if(gameArr){
        // 获取当前游戏详情
        var currentGame = gameArr.find(item => item.path === this.id)
        if (currentGame) {
          this.gameInfo.push(currentGame)
          this.authorName = currentGame.author
          document.title = currentGame.title + ' - Git游戏 - gityx.com'
          this.num = 1
          this.authorGameList = gameArr.filter(item => item.author && item.author === this.authorName && item.path !== this.id)
        }
        if (this.num < 1) {
          this.$router.push({
            path: '/'
          })
        }
      }else{
        this.getData()
      }
    },
    open() {
      $('.hide_box').fadeIn()
      $('.shang_box').fadeIn()
    },
    getArticleSetting() {
      var settingArr = JSON.parse(localStorage.getItem('settingList'))[0]
      if (localStorage.getItem('settingList')) {
        this.settingList = settingArr
        this.colorList = settingArr.article_colorList
      } else {
      var timeStamp = new Date().getTime()
      this.$http.get('static/data/setting.json' + '?' + timeStamp).then(res => {
        this.settingList = res.data[0]
        this.colorList = res.data[0].article_colorList
      },
      res => {
        console.log('error')
      }
      )
      }
    },
    getTg() {
      var timeStamp = new Date().getTime()
      this.$http.get('static/data/tuiguang.json' + '?' + timeStamp).then(res => {
        this.tgData = res.data.filter(el => el.status === 1)
      },
      res => {
        console.log('error')
      }
      )
    },
    getContents(content) {
      if (!content || content.length === 0) {
        return ['这是一款放置型经营游戏。游戏虽然没什么精美的图片和动听的音乐，但还是有相当的经营乐趣。']
      }
      return content.filter(c => c && c.length > 0)
    }
  }
}

</script>

