<script>
import SupportList from '@/components/Support.vue'
export default {
  name: 'Demo',
  components: { SupportList },
  data() {
    return {
      userList: [],
      contactList: [],
      settingList: []
    }
  },
  computed: {
    activeContactList() {
      return this.contactList.filter(item => item.status === 1)
    }
  },
  created() {
    this.getData()
    this.getAboutSetting()
    this.getContact()
  },
  mounted() {},
  methods: {
    getData() {
      var timeStamp = new Date().getTime()
      this.$http.get('static/data/user.json' + '?' + timeStamp).then(res => {
        if (res.data) {
          var data = []
          res.data.forEach(el => {
            if (el.status !== 0) {
              data.push(el)
            }
          })
          this.userList = data
        }
      },
      res => {
        console.log('error')
      }
      )
    },
    open() {
      $('.hide_box').fadeIn()
      $('.shang_box').fadeIn()
    },
    getAboutSetting() {
      if (localStorage.getItem('settingList')) {
        this.settingList = JSON.parse(localStorage.getItem('settingList'))[0]
      } else {
      var timeStamp = new Date().getTime()
      this.$http.get('static/data/setting.json' + '?' + timeStamp).then(res => {
        this.settingList = res.data[0]
      },
      res => {
        console.log('error')
      }
      )
      }
    },
    getContact() {
      var timeStamp = new Date().getTime()
      this.$http.get('static/data/contact.json' + '?' + timeStamp).then(res => {
        this.contactList = res.data
      },
      res => {
        console.log('error')
      }
      )
    },
  }
}

</script>

