<script>
import AdIndex from '@/components/Home/Ad_Top.vue'
import Slider from '@/components/Home/Slider.vue'

export default {
  name: 'Index',
  components: {
    AdIndex,
    Slider
  },
  data() {
    return {
      showNumber: 8,
      showNumberOther: 12,
      typeList: [],
      navLeftList: [],
      navRightList: [],
      gameList: [],
      gameList2: [],
      gameList3: [],
      gameList4: [],
      gameListRecent: [],
      gameListNew: [],
      gameListOther: [],
      curType: '已汉化',
      curType3: '必玩',
      curType2: '汉化中'
    }
  },
  created() {
    this.getSetting()
    // this.getData()
    this.getNavData()
  },
  computed: {
    filteredGameListNew() {
      return this.gameListNew.slice(0, this.showNumber)
    },
    filteredGameListRecent() {
      return this.gameListRecent.slice(0, this.showNumber)
    },
    filteredGameList() {
      return this.gameList.slice(0, this.showNumber)
    },
    filteredGameList2() {
      return this.gameList2.slice(0, this.showNumber)
    },
    filteredGameList3() {
      return this.gameList3.slice(0, this.showNumberOther)
    },
    filteredGameList4() {
      return this.gameList4.slice(0, this.showNumber)
    }
  },
  methods: {
    getSetting() {
      const timeStamp = new Date().getTime()
      // 获取网站配置，存入本地储存
      this.$http.get('static/data/setting.json' + '?' + timeStamp).then(game => {
        // 如果本地有记录，对比配置版本号是否一致
        if(localStorage.getItem('settingList') && (game.data[0].version === JSON.parse(localStorage.getItem('settingList'))[0].version)){
          // 读取本地json
          this.getStaticData()
        } else {
          // 覆盖本地版本号
          localStorage.setItem('settingList', JSON.stringify(game.data))
          // 读取远程json
          this.getData()
        }
      })
    },
    getData() {
      const timeStamp = new Date().getTime()
      this.$http.get('static/data/games.json' + '?' + timeStamp).then(game => {
        // 存储游戏json到本地存储
        localStorage.setItem('gameList', JSON.stringify(game.data))
        const activeGames = game.data.filter(g => g.status !== 0)
        this.gameList = activeGames.filter(g => g.type.includes(this.curType))
        this.gameList2 = activeGames.filter(g => g.type.includes(this.curType2) && !g.type.includes(this.curType)).sort((a, b) => Date.parse(b.update) - Date.parse(a.update))
        this.gameList3 = activeGames.filter(g => !g.type.includes(this.curType) && !g.type.includes(this.curType2) && !g.type.includes(this.curType3))
        this.gameList4 = activeGames.filter(g => g.type.includes(this.curType3))
        // 最近发布
        this.gameListNew = activeGames
        .filter(g => g.date)
        .sort((a, b) => Date.parse(b.date) - Date.parse(a.date))
        // 最近更新
        this.gameListRecent = activeGames
          .filter(g => g.update)
          .sort((a, b) => Date.parse(b.update) - Date.parse(a.update))
      })
    },
    getStaticData() {
       var gameArr=JSON.parse(localStorage.getItem('gameList'))
       if(gameArr){
        const activeGames = JSON.parse(localStorage.getItem('gameList')).filter(g => g.status !== 0)
        this.gameList = activeGames.filter(g => g.type.includes(this.curType))
        this.gameList2 = activeGames.filter(g => g.type.includes(this.curType2) && !g.type.includes(this.curType)).sort((a, b) => Date.parse(b.update) - Date.parse(a.update))
        this.gameList3 = activeGames.filter(g => !g.type.includes(this.curType) && !g.type.includes(this.curType2) && !g.type.includes(this.curType3))
        this.gameList4 = activeGames.filter(g => g.type.includes(this.curType3))
        // 最近发布
        this.gameListNew = activeGames
        .filter(g => g.date)
        .sort((a, b) => Date.parse(b.date) - Date.parse(a.date))
        // 最近更新
        this.gameListRecent = activeGames
          .filter(g => g.update)
          .sort((a, b) => Date.parse(b.update) - Date.parse(a.update))
        }else{
          this.getData()
        }
    },
    getNavData() {
      const timeStamp = new Date().getTime()
      this.$http.get('static/data/home_nav_box.json' + '?' + timeStamp).then(game => {
        this.navLeftList = game.data[0].left.filter(item => item.status === 1)
        this.navRightList = game.data[1].right.filter(item => item.status === 1)
      })
    },
    checkDaysDifference(date) {
      const now = new Date();
      const otherDate = new Date(date); // 示例日期，根据需要替换
      const timeDifference = now.getTime() - otherDate.getTime();
      const daysDifference = timeDifference / (1000 * 60 * 60 * 24);
      return daysDifference < 7; // 更新数据属性以供模板使用
    }
  }
}

</script>

